const e=[{label:"Servicios",href:"#servicios"},{label:"Sobre Mí",href:"#sobre-mi"},{label:"Educación",href:"#educacion"},{label:"FAQ",href:"#faq"}],a=[{question:"¿La primera consulta es gratuita?",answer:"Sí, tu primera consulta es completamente gratuita. Te haremos una revisión general de 30 minutos para evaluar tu salud bucal y crear un plan de tratamiento personalizado."},{question:"¿Puedo cambiar mi plan después?",answer:"Por supuesto. Tu plan de tratamiento es flexible y puede ajustarse en cualquier momento según tus necesidades y preferencias."},{question:"¿Cuál es la política de cancelación?",answer:"Puedes cancelar o reprogramar tu cita hasta 24 horas antes sin costo alguno. Cancelaciones tardías pueden tener un cargo mínimo."},{question:"¿Cada cuánto debo visitar al dentista?",answer:"Recomendamos visitas cada 6 meses para revisiones preventivas y limpiezas profesionales. Pacientes con tratamientos activos pueden necesitar visitas más frecuentes."},{question:"¿Qué hago en una emergencia dental?",answer:"Contáctanos inmediatamente por WhatsApp o teléfono. Reservamos espacios para emergencias y te atenderemos lo antes posible."},{question:"¿Ofrecen planes de pago o aceptan seguros?",answer:"Sí, ofrecemos planes de pago flexibles y trabajamos con las principales aseguradoras. Consulta con nosotros para más detalles."}];export{a as f,e as n};
